function Detail(props) {
  let [alerts,alerts변경] = useState(true);      
  let [inputdata,inputdata변경] = useState('');
  let 재고 = useContext(재고context);

  let [누른탭,누른탭변경] = useState(0);
  let [스위치,스위치변경] = useState(false);

  function 주문하면재고변경(index,수량){
    var newArray = [...props.재고];
    newArray[index] = newArray[index] - 수량
    props.재고변경(newArray)
  } 

  useEffect(()=>{

    axios.get()


    // 2초 후에 alert 창을 안보이게 해주어라
    let 타이머 = setTimeout(()=>{
      alerts변경(false);
    },2000)
    return function 아무이름() { clearTimeout(타이머) }
  },[]);
  useEffect(()=>{
    let 타이머 = setTimeout(()=>{
      console.log('두번째로 실행 ')
      return () => { clearTimeout(타이머)}
  })
  },[]);
  let { id } = useParams();
  let history = useHistory();
  let 찾은상품 = props.shoes.find(function(상품){
        return 상품.id == id
  })
  let 수량 = 0;
  return(
      <div className="container">
        <박스>
          <제목 className='red'>상세페이지입니다요 {재고}</제목>
        </박스>
        <input onChange = { (e) => { inputdata변경(e.target.value)} }/>
        {
          alerts === true ? <div className ="my-alert2"><p>재고가 얼마 남지 않았습니다.</p> </div> : null
        }
        <div className="row">
          <div className="col-md-6">
            <img src={"https://codingapple1.github.io/shop/shoes"+(찾은상품.id+1)+".jpg"} width="100%" />
          </div>
          <div className="col-md-6 mt-4">
            <h4 className="pt-5">{찾은상품.title}</h4>
            <p>{찾은상품.content}</p>
            <p>{찾은상품.price}</p>
            <p>{찾은상품.id}</p>
            <p>수량 : <input onChange = {(e) => { 수량 = e.target.value }}></input></p>

            <Info 재고 = {props.재고} 아이디 = {찾은상품.id}></Info>

            <button className="btn btn-danger" onClick = {()=>{ 주문하면재고변경(찾은상품.id,수량); 
            props.dispatch( {type:'항목추가',payload : { id : 찾은상품.id, name : 찾은상품.title , quan : 수량 } } );
            console.log(수량);
            history.push('/cart'); 
            } }>주문하기</button> 
            <button className="btn btn-danger" onClick ={()=>{ history.goBack()}}>뒤로가기</button> 
          </div>
        </div>

        <Nav className="mt-5" variant="tabs" defaultActiveKey="link-0">
          <Nav.Item>
            <Nav.Link eventKey="link-0" onClick = { () => { 스위치변경(false); 누른탭변경(0) }} >탭1</Nav.Link>
          </Nav.Item>
          <Nav.Item>
            <Nav.Link eventKey="link-1" onClick = { () => { 스위치변경(false); 누른탭변경(1) }}>탭2</Nav.Link>
          </Nav.Item>
          <Nav.Item>
            <Nav.Link eventKey="link-2" onClick = { () => { 스위치변경(false); 누른탭변경(2) }}>탭3</Nav.Link>
          </Nav.Item>
        </Nav>
        
        <CSSTransition in ={스위치} classNames = "wow" timeout = {500}>
        <TabContents 누른탭 = {누른탭} 스위치변경 = {스위치변경}></TabContents>
        </CSSTransition>
      </div> 
    )
}

function TabContents(props){

  useEffect(() => {
    props.스위치변경(true);
  });

  if(props.누른탭 === 0){
    return (
      <div>0번째내용입니다.</div>
    )
  }else if(props.누른탭 === 1){
    return(
      <div>1번째내용입니다.</div>
    )
  }else if(props.누른탭 === 2){
    return(
      <div>2번째내용입니다.</div>
    )
  }

}

function Info(props) {
  return(
    <p>재고 : {props.재고[props.아이디]}</p>
  )
}

function state를props화(state) {
  console.log(state)
    return{
        // 으윽 : state[0].name
        // 으으윽 : state['reducer']
        으으윽 : state.reducer,
        alert열렸니 : state['reducer2']
    }
}

export default connect(state를props화)(Detail)
